import { useGetOne } from "@workspace/api-client";
import type { Campaign } from "@workspace/api-client/types";
import type { UseGetOneOptions } from "../../../query-helpers/useGetOneQueryOptions";
import { accountCampaignsQueryKeys } from "./queryKeys";

export type UseGetCampaignParams = {
  accountId: string;
};

export const useGetCampaign = (
  id: string,
  params: UseGetCampaignParams,
  options?: Partial<UseGetOneOptions<Campaign>>,
) => {
